operations.schema:
input SetPoolRefInput {
    grantPoolsURI: URL!
    grantPoolId: PHID!
    grantPoolName: String!
}

operations.reducer:
state.grantPoolsURI = action.input.grantPoolsURI;
state.grantPoolId = action.input.grantPoolId;
state.grantPoolName = action.input.grantPoolName;

operations.schema:
input SetProjectRefInput {
    projectsURI: URL!
    projectId: PHID!
    projectName: String!
}

operations.reducer:
state.projectsURI = action.input.projectsURI;
state.projectId = action.input.projectId;
state.projectName = action.input.projectName;

operations.schema:
input AddAppSocialInput {
    id: OID!
    platform: String!
    url: URL!
}

operations.reducer:
const idx = state.socials.findIndex((s) => s.id === action.input.id);
if (idx === -1) throw new AppSocialNotFoundError(`Social ${action.input.id} not found`);
state.socials.splice(idx, 1);

operations.schema:
input AddFundsAskedInput {
    id: OID!
    amount: Amount!
}

operations.reducer:
const idx = state.fundsAsked.findIndex((f) => f.id === action.input.id);
if (idx === -1) throw new FundsAskedNotFoundError(`Funds-asked entry ${action.input.id} not found`);
state.fundsAsked.splice(idx, 1);

operations.schema:
input AddFundsApprovedInput {
    id: OID!
    amount: Amount!
}

input SetPayoutAddressInput {
    addressType: String!
    value: String!
}

operations.reducer:
state.payoutAddress = {
  addressType: action.input.addressType,
  value: action.input.value,
};

operations.schema:
input SubmitApplicationInput {
    submittedAt: DateTime!
    submitterType: AppSubmitterType!
    identifier: String!
}

operations.reducer:
const legal = ["DRAFT", "REVISED", "NEEDS_REVISION"];
if (!legal.includes(state.reviewStage)) {
  throw new InvalidSubmitTransitionError(
    `Cannot transition from ${state.reviewStage} to SUBMITTED`
  );
}
state.reviewStage = "SUBMITTED";
state.status = "pending";
state.submittedAt = action.input.submittedAt;
state.submitter = {
  submitterType: action.input.submitterType,
  identifier: action.input.identifier,
  submittedAt: action.input.submittedAt,
};

const legal = ["SUBMITTED"];
if (!legal.includes(state.reviewStage)) {
  throw new InvalidOpenTransitionError(
    `Cannot transition from ${state.reviewStage} to OPENED`
  );
}
state.reviewStage = "OPENED";
state.status = "pending";

operations.schema:
input StartReviewInput {
    reviewerDid: String!
    startedAt: DateTime!
}

operations.reducer:
const legal = ["SUBMITTED", "OPENED"];
if (!legal.includes(state.reviewStage)) {
  throw new InvalidStartReviewError(
    `Cannot transition from ${state.reviewStage} to UNDER_REVIEW`
  );
}
state.reviewStage = "UNDER_REVIEW";
state.status = "in_review";
state.reviewedBy = action.input.reviewerDid;

operations.schema:
input RequestRevisionInput {
    feedbackNotes: String!
    requestedAt: DateTime!
}

operations.reducer:
const legal = ["UNDER_REVIEW"];
if (!legal.includes(state.reviewStage)) {
  throw new InvalidRequestRevisionError(
    `Cannot transition from ${state.reviewStage} to NEEDS_REVISION`
  );
}
state.reviewStage = "NEEDS_REVISION";
state.status = "in_review";
state.feedbackNotes = action.input.feedbackNotes;

if (state.reviewStage !== "NEEDS_REVISION") {
  throw new InvalidMarkRevisedError(`Can only mark revised from NEEDS_REVISION`);
}
state.reviewStage = "REVISED";
state.status = "in_review";
state.revisionCount += 1;

operations.schema:
input ApproveApplicationInput {
    approvedAt: DateTime!
    reviewerDid: String!
}

operations.reducer:
const legal = ["UNDER_REVIEW", "REVISED"];
if (!legal.includes(state.reviewStage)) {
  throw new InvalidApproveError(
    `Cannot transition from ${state.reviewStage} to APPROVED`
  );
}
state.reviewStage = "APPROVED";
state.status = "approved";
state.reviewedBy = action.input.reviewerDid;
state.reviewedAt = action.input.approvedAt;

operations.schema:
input ConditionallyApproveInput {
    approvedAt: DateTime!
    conditions: String!
    reviewerDid: String!
}

operations.reducer:
const legal = ["UNDER_REVIEW", "REVISED"];
if (!legal.includes(state.reviewStage)) {
  throw new InvalidConditionalApproveError(
    `Cannot transition from ${state.reviewStage} to CONDITIONALLY_APPROVED`
  );
}
state.reviewStage = "CONDITIONALLY_APPROVED";
state.status = "approved";
state.reviewedBy = action.input.reviewerDid;
state.reviewedAt = action.input.approvedAt;
state.feedbackNotes = action.input.conditions;

operations.schema:
input RejectApplicationInput {
    rejectedAt: DateTime!
    reason: String!
    reviewerDid: String!
}

operations.reducer:
const legal = ["UNDER_REVIEW", "REVISED"];
if (!legal.includes(state.reviewStage)) {
  throw new InvalidRejectError(
    `Cannot transition from ${state.reviewStage} to REJECTED`
  );
}
state.reviewStage = "REJECTED";
state.status = "rejected";
state.reviewedBy = action.input.reviewerDid;
state.reviewedAt = action.input.rejectedAt;
state.feedbackNotes = action.input.reason;

operations.schema:
input WithdrawApplicationInput {
    withdrawnAt: DateTime!
    reason: String
}

operations.reducer:
if (["DRAFT", "SUBMITTED", "OPENED", "UNDER_REVIEW", "NEEDS_REVISION", "REVISED"].indexOf(state.reviewStage) === -1) {
  throw new InvalidWithdrawError(`Cannot withdraw from ${state.reviewStage}`);
}
state.reviewStage = "WITHDRAWN";
state.status = "rejected";

state.payouts.push({
  id: action.input.id,
  payoutType: action.input.payoutType,
  value: action.input.value,
  proof: action.input.proof || null,
  timestamp: action.input.timestamp,
});
state.reviewStage = "FUNDED";
state.status = "funded";

if (state.reviewStage !== "FUNDED") {
  throw new InvalidCompleteError(`Can only mark completed after FUNDED`);
}
state.reviewStage = "COMPLETED";
state.status = "completed";
